import React, { useState, useEffect } from "react";
import "../styles/Contact.css";

const Contact = () => {
  const [location, setLocation] = useState(null);

  useEffect(() => {
    if (navigator.geolocation) {
      navigator.geolocation.getCurrentPosition(
        (position) => {
          const { latitude, longitude } = position.coords;
          setLocation({ latitude, longitude });
        },
        (error) => {
          console.error("Error getting location:", error);
        }
      );
    } else {
      console.error("Geolocation is not supported by this browser.");
    }
  }, []);

  // Default location for ITS Tower (or any other place you want to use)
  const defaultLocation = {
    latitude: -6.2800964,
    longitude: 106.8339554,
  };

  // Google Map URL based on the user's location or the default one
  const googleMapUrl = location
    ? `https://www.google.com/maps/embed/v1/view?key=YOUR_GOOGLE_MAPS_API_KEY&center=${location.latitude},${location.longitude}&zoom=15`
    : `https://www.google.com/maps/embed/v1/view?key=YOUR_GOOGLE_MAPS_API_KEY&center=${defaultLocation.latitude},${defaultLocation.longitude}&zoom=15`;

  return (
    <div id="contact" className="contact-container">
      <h1>CONTACT US</h1>

      {/* Google Maps Section */}
      <div className="map-container">
        <iframe
          title="Google Map"
          className="google-map"
          src={googleMapUrl}
          allowFullScreen
          loading="lazy"
          referrerPolicy="no-referrer-when-downgrade"
        ></iframe>
      </div>

      {/* Contact Info and Form */}
      <div className="contact-content">
        <div className="contact-info">
          <h2>Law Office</h2>
          <div className="info-item">
            <span className="icon">📍</span>
            <div>
              <h3>Address</h3>
              <p>ITS Tower - Nifarro Park 8th Floor, Unit 801, 802, 817</p>
              <p>Jl. K.H. Guru Amin (F.K.A: Jl. Raya Pasar Minggu) No. 18</p>
              <p>Jakarta Selatan 12510, Indonesia</p>
            </div>
          </div>
          <div className="info-item">
            <span className="icon">📞</span>
            <div>
              <h3>Phone</h3>
              <p>+374 12 34 56 78</p>
            </div>
          </div>
          <div className="info-item">
            <span className="icon">📧</span>
            <div>
              <h3>E-mail</h3>
              <p>info@law.com</p>
            </div>
          </div>
        </div>

        <div className="contact-form">
          <h3>LEAVE US A MESSAGE</h3>
          <form>
            <input type="text" placeholder="Your Full Name" required />
            <input type="email" placeholder="example@email.com" required />
            <input type="text" placeholder="012 34 56 78" required />
            <input type="text" placeholder="Subject" required />
            <textarea placeholder="Write your message here..." required></textarea>
            <div className="recaptcha">
              <img
                src="https://www.gstatic.com/recaptcha/api2/logo_48.png"
                alt="reCAPTCHA"
              />
            </div>
            <button type="submit">Submit</button>
          </form>
        </div>
      </div>
    </div>
  );
};

export default Contact;
